import React from 'react';
import { useTema } from '../context/TemaContext';

const ControlesTema = () => {
  const { colorFondo, tamañoLetra, cambiarColorFondo, cambiarTamañoLetra, colores, tamaños } = useTema();

  return (
    <div className="controles-tema">
      <div className="control-group">
        <h3>🎨 Tema de Colores</h3>
        <div className="botones-colores">
          {Object.entries(colores).map(([key, val]) => (
            <button
              key={key}
              className={`color-btn ${colorFondo === key ? 'active' : ''}`}
              onClick={() => cambiarColorFondo(key)}
              style={{ background: val, color: key === 'claro' ? '#333' : 'white' }}
            >
              {key.charAt(0).toUpperCase() + key.slice(1)}
            </button>
          ))}
        </div>
      </div>
      <div className="control-group">
        <h3>📏 Tamaño de Letra</h3>
        <div className="botones-tamaño">
          {Object.entries(tamaños).map(([key, val]) => (
            <button
              key={key}
              className={`tamaño-btn ${tamañoLetra === key ? 'active' : ''}`}
              onClick={() => cambiarTamañoLetra(key)}
            >
              {key.charAt(0).toUpperCase() + key.slice(1)} ({val})
            </button>
          ))}
        </div>
      </div>
    </div>
  );
};

export default ControlesTema;
